package com.example.sociallogin

import android.content.Context
import android.content.Intent
import android.util.Log
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.IntentSenderRequest
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.identity.BeginSignInRequest
import com.google.android.gms.auth.api.identity.Identity
import com.google.android.gms.auth.api.identity.SignInClient

/**
 * Social login module supporting Facebook and Google OAuth.
 *
 * SECURITY ARCHITECTURE:
 * - Mobile app only holds PUBLIC client IDs (safe to embed via BuildConfig)
 * - Client SECRETS are stored ONLY on the backend server
 * - Mobile receives auth code/token -> sends to backend -> backend exchanges with secret
 * - This follows OAuth 2.0 best practices for public clients (RFC 8252)
 */

data class SocialLoginResult(
    val provider: String,
    val authToken: String,
    val userId: String?,
    val email: String?,
    val displayName: String?
)

interface SocialLoginCallback {
    fun onSuccess(result: SocialLoginResult)
    fun onError(provider: String, error: String)
    fun onCancel(provider: String)
}

class SocialLoginManager(private val activity: AppCompatActivity) {

    companion object {
        private const val TAG = "SocialLoginManager"

        // PUBLIC client IDs are safe in BuildConfig (injected from local.properties
        // via secrets-gradle-plugin, NOT hardcoded).
        // These are NOT secrets - they identify your app but can't authenticate alone.
    }

    private var callback: SocialLoginCallback? = null

    // Facebook
    private val facebookCallbackManager = CallbackManager.Factory.create()
    private val facebookLoginManager = LoginManager.getInstance()

    // Google One Tap
    private lateinit var oneTapClient: SignInClient
    private lateinit var signInRequest: BeginSignInRequest
    private lateinit var googleSignInLauncher: ActivityResultLauncher<IntentSenderRequest>

    fun initialize(loginCallback: SocialLoginCallback) {
        this.callback = loginCallback
        setupFacebookLogin()
        setupGoogleLogin()
    }

    // --- Facebook Login ---

    private fun setupFacebookLogin() {
        facebookLoginManager.registerCallback(
            facebookCallbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    val accessToken = result.accessToken
                    Log.d(TAG, "Facebook login success")

                    // IMPORTANT: Send this token to YOUR backend server.
                    // The backend uses the Facebook App Secret (stored securely on server)
                    // to verify and exchange the token.
                    sendTokenToBackendForVerification(
                        provider = "facebook",
                        token = accessToken.token,
                        userId = accessToken.userId
                    )
                }

                override fun onCancel() {
                    Log.d(TAG, "Facebook login cancelled")
                    callback?.onCancel("facebook")
                }

                override fun onError(error: FacebookException) {
                    Log.e(TAG, "Facebook login error", error)
                    callback?.onError("facebook", error.message ?: "Unknown error")
                }
            }
        )
    }

    fun loginWithFacebook() {
        facebookLoginManager.logInWithReadPermissions(
            activity,
            facebookCallbackManager,
            listOf("email", "public_profile")
        )
    }

    fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookCallbackManager.onActivityResult(requestCode, resultCode, data)
    }

    // --- Google One Tap Sign-In ---

    private fun setupGoogleLogin() {
        oneTapClient = Identity.getSignInClient(activity)

        // Only the CLIENT ID is used on mobile - this is a PUBLIC identifier, not a secret.
        // The client secret stays on your backend server.
        signInRequest = BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    .setServerClientId(BuildConfig.GOOGLE_OAUTH_CLIENT_ID)
                    .setFilterByAuthorizedAccounts(false)
                    .build()
            )
            .setAutoSelectEnabled(true)
            .build()

        googleSignInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result ->
            handleGoogleSignInResult(result.resultCode, result.data)
        }
    }

    fun loginWithGoogle() {
        oneTapClient.beginSignIn(signInRequest)
            .addOnSuccessListener(activity) { beginSignInResult ->
                try {
                    val intentSenderRequest = IntentSenderRequest.Builder(
                        beginSignInResult.pendingIntent.intentSender
                    ).build()
                    googleSignInLauncher.launch(intentSenderRequest)
                } catch (e: Exception) {
                    Log.e(TAG, "Google sign-in intent error", e)
                    callback?.onError("google", e.message ?: "Failed to launch sign-in")
                }
            }
            .addOnFailureListener(activity) { e ->
                Log.e(TAG, "Google sign-in failed", e)
                callback?.onError("google", e.message ?: "Sign-in not available")
            }
    }

    private fun handleGoogleSignInResult(resultCode: Int, data: Intent?) {
        try {
            val credential = oneTapClient.getSignInCredentialFromIntent(data)
            val idToken = credential.googleIdToken

            if (idToken != null) {
                Log.d(TAG, "Google sign-in success")

                // IMPORTANT: Send the ID token to YOUR backend server.
                // The backend verifies the token using Google's public keys
                // and uses the client secret (stored on server) for any code exchange.
                sendTokenToBackendForVerification(
                    provider = "google",
                    token = idToken,
                    userId = credential.id
                )
            } else {
                callback?.onError("google", "No ID token received")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Google credential parsing error", e)
            callback?.onError("google", e.message ?: "Failed to parse credentials")
        }
    }

    // --- Secure Token Exchange via Backend ---

    /**
     * Sends the OAuth token to your backend server for secure verification.
     *
     * WHY THIS MATTERS:
     * - The backend holds the client secrets securely (env vars, secret manager, etc.)
     * - The backend verifies the token with the OAuth provider
     * - The backend creates a session/JWT for the mobile app
     * - Client secrets NEVER touch the mobile device
     */
    private fun sendTokenToBackendForVerification(
        provider: String,
        token: String,
        userId: String?
    ) {
        // Replace with your actual backend endpoint
        BackendAuthClient.exchangeToken(
            provider = provider,
            token = token,
            onSuccess = { serverResponse ->
                callback?.onSuccess(
                    SocialLoginResult(
                        provider = provider,
                        authToken = serverResponse.sessionToken,
                        userId = serverResponse.userId,
                        email = serverResponse.email,
                        displayName = serverResponse.displayName
                    )
                )
            },
            onError = { error ->
                callback?.onError(provider, error)
            }
        )
    }

    fun logout() {
        // Facebook logout
        facebookLoginManager.logOut()
        // Google sign-out
        oneTapClient.signOut()
        Log.d(TAG, "Logged out from all providers")
    }
}

